const reveals=document.querySelectorAll(".reveal"),observer=new IntersectionObserver(e=>{e.forEach((e,r)=>{e.isIntersecting&&(setTimeout(()=>e.target.classList.add("visible"),60*r),observer.unobserve(e.target))})},{threshold:.08});function filterCards(t,e){document.querySelectorAll(".filter-btn").forEach(e=>e.classList.remove("active")),e.classList.add("active"),document.querySelectorAll(".portfolio-card").forEach(e=>{var r="all"===t||e.dataset.cat===t;e.style.display=r?"block":"none"})}reveals.forEach(e=>observer.observe(e));